document.addEventListener('DOMContentLoaded', function () {
  'use strict';

  if (window.matchMedia('(max-width: 48rem)').matches) return;

  var canvas = document.getElementById('vpn-globe-canvas');
  if (!canvas) return;

  var ctx = canvas.getContext('2d');
  var dpr = Math.min(window.devicePixelRatio || 1, 2);
  var width = 0;
  var height = 0;
  var cx = 0;
  var cy = 0;
  var radius = 0;
  var rotation = 0;
  var ROTATION_SPEED = 0.18; // radians per second
  var NUM_ARCS = 5;
  var GLOBE_COLOR = 'rgba(100, 120, 180, 0.15)';
  var DOT_RADIUS = 1 * dpr;

  // Base64-encoded land mask: 120 rows × 240 cols (1.5° resolution).
  // Each bit = 1 cell; 1 = land, 0 = ocean. Generated by scripts/generate-land-mask.js.
  var LAND_DATA = '';
  var LAND_STEP = 1.5;
  var LAND_ROWS = 120;
  var LAND_COLS = 240;
  var landPoints = []; // kept for arc endpoint selection
  var landX, landY, landZ;
  var landCount = 0;

  // Decode land mask into typed arrays of pre-computed unit-sphere XYZ
  // and a simple array for arc endpoint selection.
  (function decodeLandMask() {
    var raw = atob(LAND_DATA);
    var bytes = new Uint8Array(raw.length);
    for (var i = 0; i < raw.length; i++) bytes[i] = raw.charCodeAt(i);
    // First pass: count land cells
    var count = 0;
    for (var row = 0; row < LAND_ROWS; row++) {
      for (var col = 0; col < LAND_COLS; col++) {
        var idx = row * LAND_COLS + col;
        if (bytes[idx >> 3] & (1 << (7 - (idx & 7)))) count++;
      }
    }
    landCount = count;
    landX = new Float32Array(count);
    landY = new Float32Array(count);
    landZ = new Float32Array(count);
    // Second pass: fill typed arrays
    var n = 0;
    for (var row = 0; row < LAND_ROWS; row++) {
      var lat = 90 - (row + 0.5) * LAND_STEP;
      var phi = (90 - lat) * Math.PI / 180;
      var sinPhi = Math.sin(phi);
      var cosPhi = Math.cos(phi);
      for (var col = 0; col < LAND_COLS; col++) {
        var idx = row * LAND_COLS + col;
        if (bytes[idx >> 3] & (1 << (7 - (idx & 7)))) {
          var lon = -180 + (col + 0.5) * LAND_STEP;
          var theta = -lon * Math.PI / 180;
          landX[n] = sinPhi * Math.cos(theta);
          landY[n] = cosPhi;
          landZ[n] = sinPhi * Math.sin(theta);
          n++;
          landPoints.push({ theta: theta, phi: phi });
        }
      }
    }
  })();
  var animationId = null;
  var isVisible = true;
  var reducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

  var arcs = [];

  function resize() {
    var rect = canvas.getBoundingClientRect();
    var w = Math.round(rect.width * dpr);
    var h = Math.round(rect.height * dpr);
    if (w === 0 || h === 0) return;
    width = w;
    height = h;
    canvas.width = width;
    canvas.height = height;
    cx = width / 2;
    cy = height / 2;
    radius = Math.min(cx, cy) * 0.75;
  }

  function sphereToXYZ(theta, phi, r) {
    var x = r * Math.sin(phi) * Math.cos(theta);
    var y = r * Math.cos(phi);
    var z = r * Math.sin(phi) * Math.sin(theta);
    return { x: x, y: y, z: z };
  }

  var TILT = 0.15; // radians, tilts top toward viewer
  var cosT = Math.cos(TILT);
  var sinT = Math.sin(TILT);

  function rotateY(p, angle) {
    var cos = Math.cos(angle);
    var sin = Math.sin(angle);
    // Y-axis spin
    var x = p.x * cos + p.z * sin;
    var y = p.y;
    var z = -p.x * sin + p.z * cos;
    // X-axis tilt
    return {
      x: x,
      y: y * cosT - z * sinT,
      z: y * sinT + z * cosT
    };
  }

  function project(p) {
    return {
      x: cx + p.x,
      y: cy - p.y,
      z: p.z
    };
  }

  function angularDistance(a, b) {
    var p1 = sphereToXYZ(a.theta, a.phi, 1);
    var p2 = sphereToXYZ(b.theta, b.phi, 1);
    var dot = p1.x * p2.x + p1.y * p2.y + p1.z * p2.z;
    return Math.acos(Math.max(-1, Math.min(1, dot)));
  }

  function createArc() {
    var from, to, dist;
    var MIN_DIST = Math.PI / 6;   // 30°
    var MAX_DIST = Math.PI * 0.55; // ~100°
    do {
      from = landPoints[Math.floor(Math.random() * landPoints.length)];
      to = landPoints[Math.floor(Math.random() * landPoints.length)];
      dist = angularDistance(from, to);
    } while (dist < MIN_DIST || dist > MAX_DIST);
    return {
      from: from,
      to: to,
      progress: 0,
      speed: 0.6 + Math.random() * 0.48 // progress per second
    };
  }

  function initArcs() {
    arcs = [];
    for (var i = 0; i < NUM_ARCS; i++) {
      var arc = createArc();
      arc.progress = Math.random();
      arcs.push(arc);
    }
  }

  function slerp(from, to, t) {
    var p1 = sphereToXYZ(from.theta, from.phi, 1);
    var p2 = sphereToXYZ(to.theta, to.phi, 1);
    var dot = p1.x * p2.x + p1.y * p2.y + p1.z * p2.z;
    dot = Math.max(-1, Math.min(1, dot));
    var omega = Math.acos(dot);
    if (omega < 0.001) {
      return {
        x: p1.x + (p2.x - p1.x) * t,
        y: p1.y + (p2.y - p1.y) * t,
        z: p1.z + (p2.z - p1.z) * t
      };
    }
    var sinOmega = Math.sin(omega);
    var a = Math.sin((1 - t) * omega) / sinOmega;
    var b = Math.sin(t * omega) / sinOmega;
    return {
      x: a * p1.x + b * p2.x,
      y: a * p1.y + b * p2.y,
      z: a * p1.z + b * p2.z
    };
  }

  var OPACITY_LEVELS = [0.13, 0.17, 0.21, 0.25, 0.30, 0.35];
  var OPACITY_STYLES = [];
  for (var oi = 0; oi < OPACITY_LEVELS.length; oi++) {
    OPACITY_STYLES.push('rgba(100, 120, 180, ' + OPACITY_LEVELS[oi] + ')');
  }
  var NUM_BUCKETS = OPACITY_LEVELS.length;

  function drawGlobe() {
    // Outline circle
    ctx.strokeStyle = GLOBE_COLOR;
    ctx.lineWidth = 1 * dpr;
    ctx.beginPath();
    ctx.arc(cx, cy, radius, 0, Math.PI * 2);
    ctx.stroke();

    var cosR = Math.cos(rotation);
    var sinR = Math.sin(rotation);
    var dotSize = DOT_RADIUS * 2;
    var halfDot = DOT_RADIUS;

    // Collect dots into opacity buckets to minimize fillStyle changes.
    // Each bucket stores [sx, sy, sx, sy, ...] pairs.
    var buckets = new Array(NUM_BUCKETS);
    for (var b = 0; b < NUM_BUCKETS; b++) buckets[b] = [];

    for (var i = 0; i < landCount; i++) {
      var ux = landX[i], uy = landY[i], uz = landZ[i];
      // Inline rotateY: Y-axis spin
      var rx = ux * cosR + uz * sinR;
      var ry = uy;
      var rz = -ux * sinR + uz * cosR;
      // X-axis tilt
      var fy = ry * cosT - rz * sinT;
      var fz = ry * sinT + rz * cosT;
      if (fz < 0) continue;
      // Inline project, scale by radius
      var sx = cx + rx * radius;
      var sy = cy - fy * radius;
      // Quantize depth into bucket
      var bi = (fz * NUM_BUCKETS) | 0; // fz is 0..1 on unit sphere
      if (bi >= NUM_BUCKETS) bi = NUM_BUCKETS - 1;
      buckets[bi].push(sx, sy);
    }

    // Draw each bucket with a single fillStyle
    for (var b = 0; b < NUM_BUCKETS; b++) {
      var buf = buckets[b];
      if (buf.length === 0) continue;
      ctx.fillStyle = OPACITY_STYLES[b];
      for (var j = 0; j < buf.length; j += 2) {
        ctx.fillRect(buf[j] - halfDot, buf[j + 1] - halfDot, dotSize, dotSize);
      }
    }
  }

  function drawArcs() {
    var ARC_STEPS = 60;
    var TRAIL_LENGTH = 1.0;
    var altitude = 0.3;

    for (var a = 0; a < arcs.length; a++) {
      var arc = arcs[a];
      var tTail = Math.max(0, arc.progress - TRAIL_LENGTH);
      var tHead = Math.min(1, arc.progress);
      if (tTail >= tHead) continue;

      var prev = null;
      for (var i = 0; i <= ARC_STEPS; i++) {
        var t = tTail + (tHead - tTail) * (i / ARC_STEPS);

        var interp = slerp(arc.from, arc.to, t);
        var len = Math.sqrt(interp.x * interp.x + interp.y * interp.y + interp.z * interp.z);
        var bulge = 1 + altitude * Math.sin(Math.PI * t);
        var scale = radius * bulge / len;
        var p = { x: interp.x * scale, y: interp.y * scale, z: interp.z * scale };
        var r = rotateY(p, rotation);
        var s = project(r);

        var zFade = r.z / radius;
        var depthFade = zFade < -0.2 ? 0 : (zFade < 0.3 ? (zFade + 0.2) / 0.5 : 1);
        var trailPos = i / ARC_STEPS;
        var opacity = trailPos * 0.7 * depthFade;

        if (prev && opacity > 0.01 && prev.opacity > 0.01) {
          var segOpacity = (opacity + prev.opacity) / 2;
          ctx.beginPath();
          ctx.moveTo(prev.x, prev.y);
          ctx.lineTo(s.x, s.y);
          ctx.strokeStyle = 'rgba(100, 120, 200, ' + segOpacity + ')';
          ctx.lineWidth = 1 * dpr;
          ctx.stroke();
        }

        prev = { x: s.x, y: s.y, opacity: opacity };
      }

    }
  }

  function updateArcs(dt) {
    for (var i = 0; i < arcs.length; i++) {
      arcs[i].progress += arcs[i].speed * dt;
      if (arcs[i].progress > 2) {
        arcs[i] = createArc();
      }
    }
  }

  function draw() {
    ctx.clearRect(0, 0, width, height);
    drawGlobe();
    drawArcs();
  }

  var lastTime = 0;

  function animate(now) {
    if (!isVisible) return;
    if (!lastTime) lastTime = now;
    var dt = Math.min((now - lastTime) / 1000, 0.1); // seconds, capped to avoid jumps
    lastTime = now;
    rotation += ROTATION_SPEED * dt;
    updateArcs(dt);
    draw();
    animationId = requestAnimationFrame(animate);
  }

  function start() {
    if (animationId) return;
    if (reducedMotion) {
      draw();
      return;
    }
    lastTime = 0;
    animationId = requestAnimationFrame(animate);
  }

  function stop() {
    if (animationId) {
      cancelAnimationFrame(animationId);
      animationId = null;
    }
  }

  // Resize handling
  var ro = new ResizeObserver(function () {
    resize();
    if (!animationId && isVisible) {
      draw();
    }
  });
  ro.observe(canvas);

  // Visibility handling
  var io = new IntersectionObserver(function (entries) {
    isVisible = entries[0].isIntersecting;
    if (isVisible) {
      start();
    } else {
      stop();
    }
  }, { threshold: 0.1 });
  io.observe(canvas);

  resize();
  initArcs();
  start();
});
